// Type declarations for React Three Fiber
// These types should be automatically provided by @react-three/fiber
// but we're explicitly declaring them here for TypeScript

declare namespace JSX {
  interface IntrinsicElements {
    mesh: any;
    group: any;
    boxGeometry: any;
    meshStandardMaterial: any;
    meshBasicMaterial: any;
    lineBasicMaterial: any;
    bufferGeometry: any;
  }
}
